        private void App_DispatcherUnhandledException(object sender, DispatcherUnhandledExceptionEventArgs e)
        {
            HandleException(e.Exception, "UI线程异常");
            e.Handled = true;
        }

        private void CurrentDomain_UnhandledException(object sender, UnhandledExceptionEventArgs e)
        {
            HandleException(e.ExceptionObject as Exception, "非UI线程异常");
        }

        private void TaskScheduler_UnobservedTaskException(object sender, UnobservedTaskExceptionEventArgs e)
        {
            HandleException(e.Exception, "Task异常");
            e.SetObserved();
        }

        private void HandleException(Exception ex, string source)
        {
            if (ex == null) return;

            // 日志
            AppLog.Production.Error(ex);

            // UI 提示
            Current.Dispatcher.Invoke(() =>
            {
                MessageBox.Show(
                    $"{source}：\n{ex.Message}",
                    "程序异常",
                    MessageBoxButton.OK,
                    MessageBoxImage.Error);
            });
        }
        private void SubscribePoint()
        {
            // 订阅业务点位 PLC -> 上位机 192.168.1.10 102
            S7NetController.Instance.Subscribe("DB203.DBX0.0"); //开始/结束 1/0 测量
            S7NetController.Instance.Subscribe("DB203.DBX0.1"); //校准模式
            S7NetController.Instance.Subscribe("DB203.DBX0.2"); //测量模式
            S7NetController.Instance.Subscribe("DB203.DBX0.3"); //true 自动 false 手动
            S7NetController.Instance.Subscribe("DB203.DBX0.4"); //true 自动 false 手动
            S7NetController.Instance.Subscribe("DB203.DBD2.0"); //40位预留工件条码 （SDS + 日期 yyyyMMdd + 序列号 4 位） 
            S7NetController.Instance.Subscribe("DB203.DBD44.0"); //当前生产的零件类型 20位

